Lösung: long iteP(unsigned int k){
  long pkminus1 = 2;
  long pkminus2 = 0;
  long pkminus3 = 3;
  long result;
  if(k == 0) return 3;
  if(k == 1) return 0;
  if(k == 2) return 2;
  for(int i = 3; i<=k; i++){
