```

### Beispielergebnis

```
monate = 16
```


Lösung: int hauskauf(float sparen_emily, float sparen_sarah, int haus_kosten){
  float diff = sparen_emily + sparen_sarah - haus_kosten;
  float konto = sparen_emily + sparen_sarah;
  float zins_mult = 1.015;
  int months = 0;
  while(diff < 0){
      konto = konto * zins_mult;
      if(months % 36 == 0){
          zins_mult += 0.001;
      }
      konto += 2000;
      months++;
      diff = konto-haus_kosten;
  }
  return months;
}

