  if (x <= 0) {
    return;
  }

  while (flag) {
    if (x0 == 1) {
      printf("bestätigt!\n");
      flag = 0;
    }
    if ((x0 % 2) == 0) {
      xn = x0 / 2;
      x0 = xn;
    } else {
      xn = 3 * x0 + 1;
      if (xn < x0) {
        printf("Leider keine Aussage möglich!\n");
        flag = 0;
      }
      x0 = xn;
    }
    count++;
    if (count == INT_MAX) {
      printf("Leider keine Aussage möglich!\n");
      flag = 0;
    }
  }
}

